import { vec3 } from 'gl-matrix';
import getViewportICamera from '../getViewportICamera';
export function filterViewportsWithParallelNormals(viewports, referenceViewport, EPS = 0.999) {
    const referenceCamera = getViewportICamera(referenceViewport);
    const referenceNormal = referenceCamera.viewPlaneNormal;
    if (!referenceNormal) {
        return [];
    }
    return viewports.filter((viewport) => {
        const vpCamera = getViewportICamera(viewport);
        if (!vpCamera.viewPlaneNormal) {
            return false;
        }
        const isParallel = Math.abs(vec3.dot(vpCamera.viewPlaneNormal, referenceNormal)) > EPS;
        return isParallel;
    });
}
export default filterViewportsWithParallelNormals;
